module top_module(clk,
           reset,
           d,
           q,
           qb);input d,clk,reset;
output reg q;
output qb;



  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@ (posedge clk or posedge dbg_halt)
	begin

	if (reset)
	q = 0;
else 
	q = d;

	end
assign	qb = ~ q;

endmodule
